/**
 * Shared pipeline utilities
 *
 * Common helpers used by all data→template pipelines:
 *   - loadJson / loadTemplate
 *   - renderTemplate (dead-simple {{KEY}} replacement)
 *   - htmlEscape
 *   - tokensToPlainText (for data token arrays → mp-h2 etc)
 *   - guardUnlessGenerated (protect old hand-written HTML)
 *   - writeWithMarker (embed a "generated by pipeline" header so future runs can detect)
 */

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'fs';
import { dirname } from 'path';

export const GENERATED_MARKER = '由 build/pipelines/';

export interface TextToken {
	text: string;
	hl?: boolean;
	bold?: boolean;
	color?: string;
}

export function loadJson<T = unknown>(path: string): T {
	return JSON.parse(readFileSync(path, 'utf8')) as T;
}

export function loadTemplate(path: string): string {
	return readFileSync(path, 'utf8');
}

/**
 * Render template with {{KEY}} placeholders replaced by values from data.
 * Missing keys are replaced with empty string (warn to stderr).
 */
export function renderTemplate(template: string, data: Record<string, string | number>): string {
	const keysUsed = new Set<string>();
	let output = template.replace(/\{\{([A-Z_][A-Z0-9_]*)\}\}/g, (_match, key) => {
		keysUsed.add(key);
		if (!(key in data)) {
			console.warn(`[template] placeholder {{${key}}} not provided, replaced with ""`);
			return '';
		}
		const val = data[key];
		return val === null || val === undefined ? '' : String(val);
	});
	// Warn if data has keys not used by template
	for (const key of Object.keys(data)) {
		if (!keysUsed.has(key)) {
			console.warn(`[template] data.${key} passed but not referenced in template`);
		}
	}
	return output;
}

export function htmlEscape(s: string): string {
	return String(s ?? '').replace(/[&<>"']/g, c => (
		{ '&': '&amp;', '<': '&lt;', '>': '&gt;', '"': '&quot;', "'": '&#39;' }[c] as string
	));
}

/** Join token array's .text fields into a single plain string */
export function tokensToPlainText(tokens: TextToken[]): string {
	if (!Array.isArray(tokens)) return '';
	return tokens.map(t => t.text || '').join('');
}

/**
 * Guard: if output file exists AND doesn't contain pipeline marker, skip overwrite.
 * Returns 'write' | 'skip'.
 *
 *   'write'  — no existing file OR existing file was pipeline-generated OR force=true
 *   'skip'   — existing hand-written file, refuse to overwrite (warn to console)
 *
 * Callers should treat 'skip' as a soft no-op (not a failure), so `bun run build`
 * doesn't die just because the repo has 2026-04-21 sample files from before pipeline.
 */
export function canWriteOrSkip(outputPath: string, force = false): 'write' | 'skip' {
	if (!existsSync(outputPath)) return 'write';
	if (force) return 'write';
	const existing = readFileSync(outputPath, 'utf8');
	if (existing.includes(GENERATED_MARKER)) return 'write';
	console.warn(`[guard] SKIP ${outputPath} — hand-written (no pipeline marker). --force to overwrite.`);
	return 'skip';
}

/**
 * Write output with pipeline marker embedded (so future runs can detect this file is safe to overwrite).
 * Marker is placed in an HTML/CSS/JS comment depending on file suffix.
 */
export function writeWithMarker(
	outputPath: string,
	content: string,
	pipelineName: string,
	options?: { markdownMarkerPosition?: 'top' | 'after-frontmatter' },
): void {
	mkdirSync(dirname(outputPath), { recursive: true });
	const marker = `${GENERATED_MARKER}${pipelineName}.pipeline.ts 自动生成`;
	let withMarker = content;
	if (outputPath.endsWith('.html')) {
		// Insert marker as HTML comment after <!doctype>
		withMarker = content.replace(/^(<!doctype[^>]*>)\s*/i, (m) => `${m}\n<!-- ${marker} -->\n`);
		if (!withMarker.includes(marker)) {
			// Fallback if no doctype
			withMarker = `<!-- ${marker} -->\n${content}`;
		}
	} else if (outputPath.endsWith('.md')) {
		if (options?.markdownMarkerPosition === 'after-frontmatter') {
			const match = content.match(/^(---\n[\s\S]*?\n---\n?)/);
			if (match) {
				withMarker = `${match[1]}<!-- ${marker} -->\n${content.slice(match[1].length)}`;
			} else {
				withMarker = `<!-- ${marker} -->\n${content}`;
			}
		} else {
			withMarker = `<!-- ${marker} -->\n${content}`;
		}
	} else if (outputPath.endsWith('.css') || outputPath.endsWith('.js') || outputPath.endsWith('.ts')) {
		withMarker = `/* ${marker} */\n${content}`;
	}
	writeFileSync(outputPath, withMarker);
}

/**
 * Parse a '📎 domain-a.com · domain-b.com' src string into HTML with links.
 * For domains without full URL, prefixes with 'https://'.
 */
export function srcStringToLinks(src: string): string {
	if (!src) return '';
	const cleaned = src.replace(/^📎\s*/, '').trim();
	const parts = cleaned.split(/\s*·\s*/).map(p => p.trim()).filter(Boolean);
	const links = parts.map(p => {
		const domain = p.replace(/^https?:\/\//, '').split('/')[0];
		return `<a href="https://${domain}">${htmlEscape(p)}</a>`;
	});
	return `来源：${links.join(' · ')}`;
}
